// Parse the Gemini response and clean amounts
const input = $input.first().json;
let text = input.text || input.output || '';

// Strip markdown code blocks
text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

function parseAmt(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'number') return v;
  const cleaned = String(v).replace(/[^0-9.-]/g, '');
  const n = parseFloat(cleaned);
  return isNaN(n) ? null : Math.round(n * 100) / 100;
}

try {
  const data = JSON.parse(text);

  return [{
    json: {
      success: true,
      data: {
        vendor: data.vendor || null,
        date: data.date || null,
        amount: parseAmt(data.amount),
        category: data.category || 'Other',
        litres: parseAmt(data.litres),
        price_per_litre: parseAmt(data.price_per_litre),
        odometer_km: data.odometer_km ? parseInt(data.odometer_km) : null,
        description: data.description || null,
        rental_start: data.rental_start || null,
        rental_end: data.rental_end || null,
        rental_total: parseAmt(data.rental_total),
        vehicle_make: data.vehicle_make || null,
        vehicle_model: data.vehicle_model || null,
        vehicle_year: data.vehicle_year ? parseInt(data.vehicle_year) : null,
        vehicle_registration: data.vehicle_registration || null,
        confidence: data.confidence || null,
        notes: data.notes || null
      }
    }
  }];
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Failed to parse extraction: ' + e.message,
      raw: text
    }
  }];
}
